// src/pages/LabourDashboard.jsx

import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function LabourDashboard() {

  const user = JSON.parse(localStorage.getItem("user") || "{}");

  const [requests, setRequests] = useState([]);
  const [price, setPrice] = useState({});

  useEffect(() => {
    getRequests();
  }, []);

  const getRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/request/labour/${user._id}`
      );
      setRequests(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  const respondRequest = async (id, action) => {
    try {
      await axios.put(
        `http://localhost:5000/api/request/labour-response/${id}`,
        {
          price: price[id] || 0,
          action
        }
      );

      getRequests();
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>

        <h2 style={styles.heading}>Incoming Requests</h2>

        {requests.length === 0 && (
          <p style={styles.empty}>No requests found</p>
        )}

        {requests.map((req) => (
          <div key={req._id} style={styles.card}>

            <div style={styles.row}>
              <h3 style={styles.name}>{req.customerName}</h3>
              <span style={styles.badge}>{req.status}</span>
            </div>

            <p style={styles.text}>Work: {req.workType}</p>
            <p style={styles.text}>Location: {req.location}</p>
            <p style={styles.text}>Date: {req.date}</p>
            <p style={styles.text}>Customer Decision: {req.customerDecision}</p>

            {/* PRICE INPUT */}
            <input
              type="number"
              placeholder="Enter Price (₹)"
              style={styles.input}
              value={price[req._id] || ""}
              onChange={(e) =>
                setPrice({
                  ...price,
                  [req._id]: e.target.value
                })
              }
            />

            {/* ACTION BUTTONS */}
            {req.status === "Pending" && (
              <div style={styles.btnRow}>

                <button
                  style={styles.acceptBtn}
                  onClick={() => respondRequest(req._id, "Accepted")}
                >
                  Accept
                </button>

                <button
                  style={styles.rejectBtn}
                  onClick={() => respondRequest(req._id, "Rejected")}
                >
                  Reject
                </button>

              </div>
            )}

            {/* FEEDBACK DISPLAY */}
            {req.feedback && (
              <div style={styles.feedbackBox}>
                <h4 style={styles.rating}>
                  ⭐ {req.feedback.rating}/5
                </h4>
                <p style={styles.comment}>
                  {req.feedback.comment}
                </p>
              </div>
            )}

          </div>
        ))}

      </div>
    </div>
  );
}

/* ================= STYLES ================= */

const styles = {

  page: {
    background: "#0b0f19",
    minHeight: "100vh",
    color: "white"
  },

  container: {
    maxWidth: "900px",
    margin: "auto",
    padding: "20px"
  },

  heading: {
    color: "#f97316",
    marginBottom: "20px",
    textAlign: "center"
  },

  card: {
    background: "#111827",
    border: "1px solid #1f2937",
    borderRadius: "12px",
    padding: "18px",
    marginBottom: "15px"
  },

  row: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center"
  },

  name: {
    color: "#f97316",
    margin: 0
  },

  badge: {
    background: "#374151",
    padding: "4px 10px",
    borderRadius: "6px",
    fontSize: "12px"
  },

  text: {
    margin: "4px 0",
    color: "#d1d5db",
    fontSize: "14px"
  },

  input: {
    width: "100%",
    marginTop: "10px",
    padding: "12px",
    borderRadius: "8px",
    border: "1px solid #374151",
    background: "#1f2937",
    color: "white",
    outline: "none"
  },

  btnRow: {
    display: "flex",
    gap: "10px",
    marginTop: "12px"
  },

  acceptBtn: {
    flex: 1,
    padding: "10px",
    background: "#16a34a",
    border: "none",
    borderRadius: "8px",
    color: "white",
    cursor: "pointer"
  },

  rejectBtn: {
    flex: 1,
    padding: "10px",
    background: "#dc2626",
    border: "none",
    borderRadius: "8px",
    color: "white",
    cursor: "pointer"
  },

  feedbackBox: {
    marginTop: "12px",
    background: "#1f2937",
    padding: "12px",
    borderRadius: "10px",
    border: "1px solid #374151"
  },

  rating: {
    margin: "0 0 5px 0",
    color: "#f97316"
  },

  comment: {
    margin: 0,
    color: "#d1d5db"
  },

  empty: {
    textAlign: "center",
    color: "#9ca3af"
  }
};
